(function() {
    tinymce.PluginManager.add('ultable', function(editor, url) {
        editor.addButton('ultable', {
            title: 'Convert UL ↔ Table',
            text: 'UL ↔ Table',
            onclick: function() {
                try {
                    var node = editor.dom.getParent(editor.selection.getStart(), 'ul,table');
                    if (!node) {
                        editor.windowManager.alert('Place the cursor inside a UL or TABLE.');
                        return;
                    }
                    if (node.nodeName === 'UL') {
                        var html = '<table><tbody>';
                        node.querySelectorAll('li').forEach(function(li) {
                            var parts = li.textContent.split(':');
                            var col1 = parts[0] ? parts[0].trim() : '';
                            var col2 = parts[1] ? parts.slice(1).join(':').trim() : '';
                            html += '<tr><td>' + col1 + '</td><td>' + col2 + '</td></tr>';
                        });
                        html += '</tbody></table>';
                        editor.dom.replace(editor.dom.createFragment(html), node);
                    } else if (node.nodeName === 'TABLE') {
                        var html = '<ul>';
                        node.querySelectorAll('tr').forEach(function(tr) {
                            var tds = tr.querySelectorAll('td');
                            var col1 = tds[0] ? tds[0].textContent.trim() : '';
                            var col2 = tds[1] ? tds[1].textContent.trim() : '';
                            var liText = col1;
                            if (col2 !== '') {
                                liText += ': ' + col2;
                            }
                            html += '<li>' + liText + '</li>';
                        });
                        html += '</ul>';
                        editor.dom.replace(editor.dom.createFragment(html), node);
                    } else {
                        editor.windowManager.alert('Place the cursor inside a UL or TABLE.');
                    }
                } catch (e) {
                    console.error('UL ↔ Table Error:', e);
                    editor.windowManager.alert('An error occurred while converting.');
                }
            }
        });
    });
})();
